#!/bin/sh
# cargo-loco-generate/cargo-loco-generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding pre-operative-assessment-by-patient (8 tables)..."

cargo loco generate scaffold patient \
    deleted_at:ts \
    name:string! \
    birth_date:date \
    united_kingdom_nhs_number:string^ \
    waist_as_cm:double \
    height_as_cm:double \
    weight_as_kg:double \
    body_mass_index:double \
    waist_height_ratio:double \
    vo2_max:double \
    --htmx && \
cargo loco generate scaffold clinician \
    deleted_at:ts \
    name:text! \
    role:text! \
    registration_body:text! \
    registration_number:text! \
    united_kingdom_nhs_number:string^ \
    --htmx && \
cargo loco generate scaffold pre_operative_assessment_by_patient \
    patient:references \
    weight:double \
    height:double \
    bmi:double \
    planned_procedure:text! \
    procedure_urgency:text! \
    status:text! \
    hypertension:text! \
    hypertension_controlled:text! \
    ischemic_heart_disease:text! \
    ihd_details:text! \
    heart_failure:text! \
    heart_failure_nyha:text! \
    valvular_disease:text! \
    valvular_details:text! \
    arrhythmia:text! \
    arrhythmia_type:text! \
    pacemaker:text! \
    recent_mi:text! \
    recent_mi_weeks:int \
    asthma:text! \
    asthma_frequency:text! \
    copd:text! \
    copd_severity:text! \
    osa:text! \
    osa_cpap:text! \
    smoking:text! \
    smoking_pack_years:int \
    recent_urti:text! \
    ckd:text! \
    ckd_stage:text! \
    dialysis:text! \
    dialysis_type:text! \
    liver_disease:text! \
    cirrhosis:text! \
    child_pugh_score:text! \
    hepatitis:text! \
    hepatitis_type:text! \
    diabetes:text! \
    diabetes_control:text! \
    diabetes_on_insulin:text! \
    thyroid_disease:text! \
    thyroid_type:text! \
    adrenal_insufficiency:text! \
    stroke_or_tia:text! \
    stroke_details:text! \
    epilepsy:text! \
    epilepsy_controlled:text! \
    neuromuscular_disease:text! \
    neuromuscular_details:text! \
    raised_icp:text! \
    bleeding_disorder:text! \
    bleeding_details:text! \
    on_anticoagulants:text! \
    anticoagulant_type:text! \
    sickle_cell_disease:text! \
    sickle_cell_trait:text! \
    anaemia:text! \
    rheumatoid_arthritis:text! \
    cervical_spine_issues:text! \
    limited_neck_movement:text! \
    limited_mouth_opening:text! \
    dental_issues:text! \
    dental_details:text! \
    previous_difficult_airway:text! \
    mallampati_score:text! \
    gord:text! \
    hiatus_hernia:text! \
    nausea:text! \
    name:text! \
    dose:text! \
    frequency:text! \
    sort_order:int! \
    allergen:text! \
    reaction:text! \
    severity:text! \
    allergy_sort_order:int! \
    previous_anaesthesia:text! \
    anaesthesia_problems:text! \
    anaesthesia_problem_details:text! \
    family_mh_history:text! \
    family_mh_details:text! \
    ponv:text! \
    alcohol:text! \
    alcohol_units_per_week:int \
    recreational_drugs:text! \
    drug_details:text! \
    exercise_tolerance:text! \
    estimated_mets:double \
    mobility_aids:text! \
    recent_decline:text! \
    possibly_pregnant:text! \
    pregnancy_confirmed:text! \
    gestation_weeks:int \
    --htmx && \
cargo loco generate scaffold asa_rule \
    system:text! \
    description:text! \
    grade:int! \
    --htmx && \
cargo loco generate scaffold clinician \
    name:text! \
    role:text! \
    registration_body:text! \
    registration_number:text! \
    united_kingdom_nhs_number:string^ \
    --htmx && \
cargo loco generate scaffold grading_result \
    pre_operative_assessment_by_patient:references \
    computed_asa_grade:string! \
    final_asa_grade:string! \
    asa_emergency_suffix:string! \
    override_reason:string! \
    mallampati_class:string! \
    rcri_score:int \
    stopbang_score:int \
    frailty_scale:int \
    composite_risk:string! \
    recommendation:string! \
    clinician_notes:text! \
    signed_at:ts \
    graded_at:ts! \
    --htmx && \
cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    instrument:string! \
    grade:string! \
    category:string! \
    description:string! \
    --htmx && \
cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    priority:string! \
    description:string! \
    suggested_action:string! \
    --htmx

echo "Done."
